perspectives.style:
@settings {
  template: stakeholder;
}

element {
  color: #ffffff;
  size: scale("influence", 20, 100);
  min-size: 20;
  image-fit: contain;
  border-width: scale("influence", 1.5, 5);
  border-color: #9aa4b2;
  font-size: 13;
}

element["element type"="Person"]  { border-color: #ff6b6b; image-fit: cover; }
element["element type"="Project"] { border-color: #4ecdc4; image-fit: contain; }

connection { color: #b0b7c0; width: 1.5; arrow-size: 6; }

